# -*- coding: utf-8 -*-
from __future__ import annotations
import argparse
import base64
import socket
import webbrowser
from http import HTTPStatus
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer

HTML_B64 = """"""
CSS_B64 = """"""
JS_B64 = """"""
UPGRADE_JS = r"""
(function () {
  const STORAGE_KEY = "safety-doc-checklist-v1";
  function getEl(id) { return document.getElementById(id); }
  function currentState() {
    return {
      projectName: getEl("projectName")?.value || "",
      companyName: getEl("companyName")?.value || "",
      contractAmount: getEl("contractAmount")?.value || "50",
      contractPeriod: getEl("contractPeriod")?.value || "12"
    };
  }
  function saveState() { try { localStorage.setItem(STORAGE_KEY, JSON.stringify(currentState())); } catch (e) {} }
  function restoreState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const s = JSON.parse(raw);
      if (getEl("projectName")) getEl("projectName").value = s.projectName || "";
      if (getEl("companyName")) getEl("companyName").value = s.companyName || "";
      if (getEl("contractAmount")) getEl("contractAmount").value = s.contractAmount || "50";
      if (getEl("contractPeriod")) getEl("contractPeriod").value = s.contractPeriod || "12";
      if (getEl("contractAmountInput")) getEl("contractAmountInput").value = s.contractAmount || "50";
      if (getEl("contractPeriodInput")) getEl("contractPeriodInput").value = s.contractPeriod || "12";
      if (typeof updateSliderValues === "function") updateSliderValues();
      if (typeof generateAllPages === "function") generateAllPages();
      if (typeof updateDocumentCounts === "function") {
        const amount = parseFloat(getEl("contractAmount")?.value || "50");
        const period = parseFloat(getEl("contractPeriod")?.value || "12");
        updateDocumentCounts(amount, period);
      }
    } catch (e) {}
  }
  function wireAutosave() {
    ["projectName", "companyName", "contractAmount", "contractPeriod", "contractAmountInput", "contractPeriodInput"].forEach((id) => {
      const el = getEl(id);
      if (!el) return;
      el.addEventListener("input", saveState);
      el.addEventListener("change", saveState);
    });
  }
  window.resetForm = function () {
    if (getEl("projectName")) getEl("projectName").value = "";
    if (getEl("companyName")) getEl("companyName").value = "";
    if (getEl("contractAmount")) getEl("contractAmount").value = "50";
    if (getEl("contractPeriod")) getEl("contractPeriod").value = "12";
    if (getEl("contractAmountInput")) getEl("contractAmountInput").value = "50";
    if (getEl("contractPeriodInput")) getEl("contractPeriodInput").value = "12";
    if (typeof updateSliderValues === "function") updateSliderValues();
    if (typeof generateAllPages === "function") generateAllPages();
    if (typeof updateDocumentCounts === "function") updateDocumentCounts(50, 12);
    try { localStorage.removeItem(STORAGE_KEY); } catch (e) {}
  };
  window.addEventListener("beforeunload", saveState);
  restoreState();
  wireAutosave();
})();
"""

def build_html_bytes() -> bytes:
    html = base64.b64decode(HTML_B64)
    css = base64.b64decode(CSS_B64)
    js = base64.b64decode(JS_B64)
    html = html.replace(b'<link rel="stylesheet" href="style.css">', b"<style>" + css + b"</style>")
    html = html.replace(b'<script src="script.js"></script>', b"<script>" + js + b"</script>" + b"<script>" + UPGRADE_JS.encode("utf-8") + b"</script>")
    return html

HTML_BYTES = build_html_bytes()

class Handler(BaseHTTPRequestHandler):
    def do_GET(self) -> None:
        if self.path in ("/", "/index.html"):
            self.send_response(HTTPStatus.OK)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Cache-Control", "no-store")
            self.end_headers()
            self.wfile.write(HTML_BYTES)
            return
        self.send_response(HTTPStatus.NOT_FOUND)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.end_headers()
        self.wfile.write(b"Not Found")
    def log_message(self, format: str, *args) -> None:
        return

def find_free_port(preferred: int) -> int:
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        if s.connect_ex(("127.0.0.1", preferred)) != 0:
            return preferred
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.bind(("127.0.0.1", 0))
        return int(s.getsockname()[1])

def main() -> None:
    parser = argparse.ArgumentParser(description="Run Safety Document checklist single-file server")
    parser.add_argument("--host", default="127.0.0.1")
    parser.add_argument("--port", type=int, default=8000)
    parser.add_argument("--no-browser", action="store_true")
    args = parser.parse_args()
    port = find_free_port(args.port)
    server = ThreadingHTTPServer((args.host, port), Handler)
    url = f"http://{args.host}:{port}"
    print(f"Serving at {url}")
    if not args.no_browser:
        webbrowser.open(url)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        server.server_close()
        print("Server stopped.")

if __name__ == "__main__":
    main()
